private void writeBits(final DataOutput header, final BitSet bits, final int length) throws IOException {
        int cache = 0;
        int shift = 7;
        for (int i = 0; i < length; i++) {
            if (bits.get(i)) {
                cache |= (1 << shift);
            }
            --shift;
            if (shift < 0) {
                header.write(cache);
                shift = 7;
                cache = 0;
            }
        }
        if (length > 0 && shift != 7) {
            header.write(cache);
        }
    }

